const INSTANCE_ID = $('Set Instance Context').first().json.INSTANCE_ID;

const USE_HIGH_RES_TS = true;

const ROUND_SECONDS = 60;

const RESPECT_LINE_TIMESTAMPS = false;

const inItem = $input.first().json;
const raw = inItem.data ?? '';
if (typeof raw !== 'string' || raw.length === 0) {
  return [{ json: { error: 'No metrics text found in $json.data', gotType: typeof raw } }];
}
const text = raw.includes('\\n') ? raw.replace(/\\n/g, '\n') : raw;

function roundedNowIso(roundSeconds) {
  const ms = Date.now();
  const step = roundSeconds * 1000;
  const rounded = Math.floor(ms / step) * step;
  return new Date(rounded).toISOString();
}

function nowIso() {
  return new Date().toISOString();
}

function parseLabels(labelsStr) {
  if (!labelsStr) return {};
  const parts = labelsStr.split(/,(?=(?:[^"]*"[^"]*")*[^"]*$)/);
  const labels = {};
  for (const part of parts) {
    const p = part.trim();
    if (!p) continue;
    const eq = p.indexOf('=');
    if (eq === -1) continue;
    const key = p.slice(0, eq).trim();
    let val = p.slice(eq + 1).trim();
    val = val.replace(/^"|"$/g, '');
    val = val.replace(/\\"/g, '"');
    val = val.replace(/\\\\/g, '\\');
    labels[key] = val;
  }
  return labels;
}

function canonicalLabels(labelsObj) {
  const keys = Object.keys(labelsObj).sort();
  const out = {};
  for (const k of keys) out[k] = labelsObj[k];
  return out;
}

function labelsHash(labelsObj) {
  return JSON.stringify(canonicalLabels(labelsObj));
}

function seriesKey(instanceId, metricName, labelsHashVal) {
  return `${instanceId}||${metricName}||${labelsHashVal}`;
}

function hasNoLabels(s) {
  return !s.labels || Object.keys(s.labels).length === 0;
}

function findNoLabelValue(samples, patterns) {
  for (const re of patterns) {
    const s = samples.find(x => re.test(x.name) && hasNoLabels(x));
    if (s && Number.isFinite(s.value)) return s.value;
  }
  return null;
}

function findLabelValue(samples, namePatterns, labelKeys) {
  for (const re of namePatterns) {
    const s = samples.find(x => re.test(x.name));
    if (!s || !s.labels) continue;
    for (const k of labelKeys) {
      if (s.labels[k] != null) return String(s.labels[k]);
    }
  }
  return null;
}

function baseNameForSuffixMetric(name) {
  const m = name.match(/^(.*)_(bucket|sum|count)$/);
  return m ? m[1] : null;
}

function normalizeType(name, directType, typeByBaseName) {
  if (directType) return directType;
  const base = baseNameForSuffixMetric(name);
  if (!base) return null;
  return typeByBaseName.get(base) ?? null;
}

const helpByName = new Map();
const typeByName = new Map();
const typeByBaseName = new Map();
const samples = [];

const SCRAPE_TS = USE_HIGH_RES_TS ? nowIso() : roundedNowIso(ROUND_SECONDS);

const metricLineRe =
  /^([a-zA-Z_:][a-zA-Z0-9_:]*)(\{([^}]*)\})?\s+([+-]?\d+(\.\d+)?([eE][+-]?\d+)?|NaN|\+Inf|-Inf)(\s+(\d+))?$/;

for (const line of text.split('\n')) {
  const l = line.trim();
  if (!l) continue;

  if (l.startsWith('# HELP ')) {
    const m = l.match(/^# HELP ([^\s]+)\s+(.+)$/);
    if (m) helpByName.set(m[1], m[2]);
    continue;
  }

  if (l.startsWith('# TYPE ')) {
    const m = l.match(/^# TYPE ([^\s]+)\s+([^\s]+)$/);
    if (m) {
      const metric = m[1];
      const t = m[2];
      typeByName.set(metric, t);
      typeByBaseName.set(metric, t);
    }
    continue;
  }

  if (l.startsWith('#')) continue;

  const m = l.match(metricLineRe);
  if (!m) continue;

  const name = m[1];
  const labelsStr = m[3] || '';
  const rawValue = m[4];
  const tsRaw = m[8] ? Number(m[8]) : null;

  const value = Number(rawValue);
  if (!Number.isFinite(value)) continue;

  const ts = (RESPECT_LINE_TIMESTAMPS && tsRaw)
    ? new Date(tsRaw).toISOString()
    : SCRAPE_TS;

  const labels = parseLabels(labelsStr);
  const directType = typeByName.get(name) ?? null;
  const metric_type = normalizeType(name, directType, typeByBaseName);
  let help = helpByName.get(name) ?? null;
  if (!help) {
    const base = baseNameForSuffixMetric(name);
    if (base) help = helpByName.get(base) ?? null;
  }

  samples.push({
    name,
    labels,
    value,
    metric_type,
    help,
    ts,
  });
}

const seriesMap = new Map();
const sampleMap = new Map();

for (const s of samples) {
  const labels = canonicalLabels(s.labels || {});
  const lh = labelsHash(labels);
  const key = seriesKey(INSTANCE_ID, s.name, lh);

  if (!seriesMap.has(key)) {
    seriesMap.set(key, {
      key,
      instance_id: INSTANCE_ID,
      metric_name: s.name,
      labels,
      labels_hash: lh,
      metric_type: s.metric_type,
      help: s.help,
    });
  }
  const sampleKey = `${key}||${s.ts}`;
  sampleMap.set(sampleKey, { key, ts: s.ts, value: s.value });
}

const seriesRows = Array.from(seriesMap.values());
const sampleRows = Array.from(sampleMap.values());
const snapshotParams = {
  ts: SCRAPE_TS,
  instance_id: INSTANCE_ID,

  n8n_version: findLabelValue(
  samples,
  [/^n8n_(?!nodejs_).*version.*info$/i],
  ['version', 'n8n_version', 'build_version', 'release']
),
  node_version: findLabelValue(
    samples,
    [/node(js)?_version.*info/i, /n8n.*node.*version.*info/i, /.*node.*version.*/i],
    ['version', 'node_version', 'runtime_version']
  ),

  process_start_time_seconds: findNoLabelValue(samples, [/process_start_time_seconds$/i]),

  is_leader: (() => {
    const v = findNoLabelValue(samples, [/instance_role_leader$/i, /leader$/i]);
    return v === null ? null : v === 1;
  })(),
  active_workflows: findNoLabelValue(samples, [/active_workflow_count$/i, /active_workflows$/i]),

  cpu_total_seconds: findNoLabelValue(samples, [/process_cpu_seconds_total$/i, /cpu_seconds_total$/i]),
  memory_rss_bytes: findNoLabelValue(samples, [/resident_memory_bytes$/i, /memory_rss_bytes$/i, /process_resident_memory_bytes$/i]),
  heap_used_bytes: findNoLabelValue(samples, [/heap_size_used_bytes$/i, /heap_used_bytes$/i]),
  external_memory_bytes: findNoLabelValue(samples, [/external_memory_bytes$/i]),
  eventloop_lag_p99_s: findNoLabelValue(samples, [/eventloop_lag_p99_seconds$/i, /event_loop_lag_p99.*seconds$/i]),
  open_fds: findNoLabelValue(samples, [/process_open_fds$/i, /open_fds$/i]),
};

return [{
  json: {
    INSTANCE_ID,
    scrape_ts: SCRAPE_TS,
    snapshotParams,
    seriesRows,
    sampleRows,
    counts: {
      parsed_samples: samples.length,
      unique_series: seriesRows.length,
      unique_samples: sampleRows.length,
    },
    config: {
      USE_HIGH_RES_TS,
      ROUND_SECONDS: USE_HIGH_RES_TS ? null : ROUND_SECONDS,
      RESPECT_LINE_TIMESTAMPS,
    }
  }
}];
